ret.z = GetPixel(uv_z).z - (GetBlur1(vUv).z-GetPixel(uv_z).z)*0.024 - 0.009 + (0+GetPixel(vUvOriginal).x)*0.014 + rand*0.02;

ret.x = texture( sampler_fc_main, vUv+rand*uTexSize.zw*.5 ).x;
ret.x += (ret.x - GetBlur3(vUv).x)*0.4 + rand*0.004;

